async (page) => {
  // Click on the Programmer NPC visible in the screenshot (upper right area with blue indicator)
  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 810, y: 265 });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}

