async (page) => {
  // Open inventory to see all items
  await page.evaluate(() => document.getElementById('inventory-button').click());
  await page.waitForTimeout(1000);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  // Check inventory DOM for items
  const invItems = await page.evaluate(() => {
    const slots = document.querySelectorAll('.item-slot');
    const items = [];
    slots.forEach((slot, i) => {
      if (slot.innerHTML.includes('item')) {
        items.push({index: i, html: slot.innerHTML.substring(0, 100)});
      }
    });
    return items;
  });

  // Close inventory
  await page.evaluate(() => document.getElementById('inventory-button').click());

  return JSON.stringify({invItems: invItems.length, firstFew: invItems.slice(0,5)});
}

