    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Blacksmith at (199, 169), I'm at (196, 162). Walk to it.
  await click(760, 620);
  await page.waitForTimeout(3000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return { pos: gs.player_position, hp: gs.player_stats.hp,
      nearby_npcs: (gs.nearby_entities || []).filter(e => e.type === 1 && e.distance < 15).map(e => ({name: e.name, x: e.x, y: e.y, dist: e.distance, cx: e.click_x, cy: e.click_y, quest: e.quest_npc}))
    };
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

async (page) => {
  // Blacksmith at (199,169), player at (198,170): delta (1,-1) -> screen (688, 312)
  await page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, { x: 688, y: 312 });
  await page.waitForTimeout(1500);

  // Check for dialogue or quest panel
  const info = await page.evaluate(() => {
    const q = document.getElementById('quest');
    const questVisible = q ? window.getComputedStyle(q).display !== 'none' : false;
    // Check for any visible dialogue/notification
    const notif = document.getElementById('notifications');
    const notifVisible = notif ? window.getComputedStyle(notif).display !== 'none' : false;
    // Check chat
    const bubbles = Array.from(document.querySelectorAll('.bubble-text, .speech-bubble, [class*="bubble"]')).map(el => el.textContent).filter(t => t.trim());
    return { questVisible, notifVisible, bubbles };
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify(info);
}

