async (page) => {
  // Click on the Rat immediately using fresh coords
  await page.evaluate(() => {
    const gs = window.__latestGameState;
    const TILE = 48, CX = 640, CY = 360;
    const px = gs.player_position.x, py = gs.player_position.y;
    const rat = (gs.nearby_entities || []).filter(e => e.name === 'Rat' && e.distance <= 5)
      .sort((a, b) => a.distance - b.distance)[0];
    if (rat) {
      const sx = CX + (rat.x - px) * TILE;
      const sy = CY + (rat.y - py) * TILE;
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: sx, clientY: sy, bubbles: true }));
    }
  });
  await page.waitForTimeout(4000);

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const drops = (gs.nearby_entities || []).filter(e => e.type === 4);
    return {
      pos: gs.player_position, hp: gs.player_stats.hp, level: gs.player_stats.level,
      target: gs.current_target ? {name: gs.current_target.name, hp: gs.current_target.hp} : null,
      drops: drops.map(d => ({name: d.name, cx: d.click_x, cy: d.click_y, dist: d.distance}))
    };
  });
  return JSON.stringify(state);
}

