        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, { x: CX, y: CY - 300 });
      await page.waitForTimeout(5000);
      continue;
    }

    // Check for drops
    const drop = gs.nearby_entities.find(e => e.type === 4 && e.distance <= 5);
    if (drop) {
      const sx = CX + (drop.x - pos.x) * TILE;
      const sy = CY + (drop.y - pos.y) * TILE;
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, { x: sx, y: sy });
      results.push('Looted: ' + drop.name);
      await page.waitForTimeout(2000);
      continue;
    }

    // Find Spooky Skeleton
    const skeleton = gs.nearby_entities.find(e => e.type === 3 && e.name.includes('Skeleton') && e.distance <= 25);
    if (!skeleton) {
      // Walk south to find skeletons
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, { x: CX + 100, y: CY + 300 });
      results.push('Walking south, pos=' + JSON.stringify(pos));
      await page.waitForTimeout(3000);
      continue;
    }

    const sx = CX + (skeleton.x - pos.x) * TILE;
    const sy = CY + (skeleton.y - pos.y) * TILE;
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: sx, y: sy });
    await page.waitForTimeout(6000);
    kills++;
    results.push(`Kill ${kills}: ${skeleton.name} at (${skeleton.x},${skeleton.y}) d=${skeleton.distance}`);

    if (kills >= 5) break;
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const gs2 = await page.evaluate(() => window.__latestGameState);
  return JSON.stringify({
    results: results.slice(-8),
    kills,
    pos: gs2.player_position,
    hp: gs2.player_stats.hp + '/' + gs2.player_stats.max_hp,
    inventory: gs2.inventory,
    anvilQ: gs2.quests.find(q => q.key === 'anvilsechoes')
  });
}

