async (page) => {
  const TILE = 48, CX = 640, CY = 360;
  let kills = 0;
  const results = [];

  for (let i = 0; i < 30; i++) {
    const gs = await page.evaluate(() => window.__latestGameState);
    const pos = gs.player_position;

    // HP check
    if (gs.player_stats.hp < gs.player_stats.max_hp * 0.4) {
      results.push('LOW HP ' + gs.player_stats.hp);
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, { x: CX - 200, y: CY - 200 });
      await page.waitForTimeout(5000);
      continue;
    }

    // Grab drops
    const drop = gs.nearby_entities.find(e => e.type === 4 && e.distance <= 5);
    if (drop) {
      const sx = CX + (drop.x - pos.x) * TILE;
      const sy = CY + (drop.y - pos.y) * TILE;
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, { x: sx, y: sy });
      results.push('Looted: ' + drop.name);
      await page.waitForTimeout(2000);
      continue;
    }

    // Target Batterflies first, then other mobs
    const mobs = gs.nearby_entities.filter(e => e.type === 3 && e.distance <= 15);
    const target = mobs.find(e => e.name === 'Batterfly') || mobs.sort((a,b) => a.distance - b.distance)[0];

    if (!target) {
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, { x: CX - 200, y: CY });
      results.push('No mobs, walking west');
      await page.waitForTimeout(3000);
