async (page) => {
  const TILE = 48, CX = 640, CY = 360;
  let kills = 0;
  let hammerFound = false;

  for (let i = 0; i < 30; i++) {
    const gs = await page.evaluate(() => window.__latestGameState);
    const pos = gs.player_position;
    const hp = gs.player_stats.hp, maxhp = gs.player_stats.max_hp;

    // Heal if needed
    if (hp < maxhp * 0.4) {
      const food = gs.inventory.find(e => e.edible);
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(500);
      }
    }

    // Check for drops (hammer!)
    const drops = gs.nearby_entities.filter(e => e.type === 4);
    if (drops.length > 0) {
      const drop = drops[0];
      const cx = CX + (drop.x - pos.x) * TILE;
      const cy = CY + (drop.y - pos.y) * TILE;
      await page.evaluate(({x, y}) => {
        document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
      }, { x: cx, y: cy });
      await page.waitForTimeout(2000);
      console.log('Looted drop:', drop.name, drop.key);
      if (drop.name && drop.name.toLowerCase().includes('hammer')) hammerFound = true;
      continue;
    }

    // Find nearest crab
    const crab = gs.nearby_entities.find(e => e.name === 'Crab' && e.type === 3);
    if (!crab) {
      await page.waitForTimeout(2000);
      continue;
    }

    const cx = CX + (crab.x - pos.x) * TILE;
    const cy = CY + (crab.y - pos.y) * TILE;
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: Math.max(1, Math.min(1279, cx)), y: Math.max(1, Math.min(719, cy)) });
    await page.waitForTimeout(5000);
    kills++;
    console.log(`Kill ${kills} at`, JSON.stringify(crab), 'pos:', JSON.stringify(pos));
  }

  const gs = await page.evaluate(() => window.__latestGameState);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return JSON.stringify({ pos: gs.player_position, kills, hammerFound, inv: gs.inventory });
}

