async (page) => {
  const TILE = 48, CX = 640, CY = 360;

  // Explore east along the beach looking for dungeon entrance or new entity types
  const waypoints = [
    { x: 150, y: 225 }, // east
    { x: 180, y: 215 }, // further east/north
