  ];

  for (const wp of waypoints) {
    const gs = await page.evaluate(() => window.__latestGameState);
    const pos = gs.player_position;
    const dx = wp.x - pos.x, dy = wp.y - pos.y;
    const dist = Math.sqrt(dx*dx + dy*dy);
    const steps = Math.min(8, dist);
    const sx = Math.max(1, Math.min(1279, CX + (dx/dist)*steps*TILE));
    const sy = Math.max(1, Math.min(719, CY + (dy/dist)*steps*TILE));

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: sx, y: sy });
    await page.waitForTimeout(3500);

    // Check for new entity types
    const gs2 = await page.evaluate(() => window.__latestGameState);
    const types = new Set(gs2.nearby_entities.map(e => e.type));
    const newTypes = [...types].filter(t => ![1,3,10,12].includes(t));
    const drops = gs2.nearby_entities.filter(e => e.type === 4);
    if (newTypes.length > 0 || drops.length > 0) {
      console.log('NEW TYPES/DROPS at', JSON.stringify(gs2.player_position), newTypes, drops);
    }
    console.log('pos:', JSON.stringify(gs2.player_position));
  }

  const gs = await page.evaluate(() => window.__latestGameState);
  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });

  // Check all unique entity types in extended area
  const allTypes = {};
  gs.nearby_entities.forEach(e => {
    if (!allTypes[e.type]) allTypes[e.type] = [];
    if (allTypes[e.type].length < 2) allTypes[e.type].push({ name: e.name, dist: e.distance });
  });

  return JSON.stringify({ pos: gs.player_position, allTypes });
}

