async (page) => {
  const TILE = 48, CX = 640, CY = 360;

  // SA at (137, 171), player at (129, 170)
  // cx = 640 + (137-129)*48 = 640 + 384 = 1024
  // cy = 360 + (171-170)*48 = 360 + 48 = 408
  // That's at edge of screen, try smaller steps

  for (let i = 0; i < 10; i++) {
    const gs = await page.evaluate(() => window.__latestGameState);
    const pos = gs.player_position;
    const sa = gs.nearby_entities.find(e => e.name === 'Secret Agent');
    if (sa && sa.distance <= 3) break;

    const dx = 137 - pos.x, dy = 171 - pos.y;
    const dist = Math.sqrt(dx*dx + dy*dy);
    if (dist < 2) break;

    const steps = Math.min(3, dist);
    const sx = Math.max(1, Math.min(1279, CX + (dx/dist)*steps*TILE));
    const sy = Math.max(1, Math.min(719, CY + (dy/dist)*steps*TILE));
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: sx, y: sy });
    await page.waitForTimeout(2500);

    const gs2 = await page.evaluate(() => window.__latestGameState);
    const sa2 = gs2.nearby_entities.find(e => e.name === 'Secret Agent');
    console.log('pos:', JSON.stringify(gs2.player_position), 'SA:', sa2 ? sa2.distance : '?');
  }

  const gs = await page.evaluate(() => window.__latestGameState);
  const sa = gs.nearby_entities.find(e => e.name === 'Secret Agent');

  if (sa && sa.distance <= 3) {
    const pos = gs.player_position;
    const cx = Math.max(1, Math.min(1279, CX + (sa.x - pos.x)*TILE));
    const cy = Math.max(1, Math.min(719, CY + (sa.y - pos.y)*TILE));
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
    }, { x: cx, y: cy });
    await page.waitForTimeout(2000);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const gs2 = await page.evaluate(() => window.__latestGameState);
  const sa2 = gs2.nearby_entities.find(e => e.name === 'Secret Agent');
  return JSON.stringify({ pos: gs2.player_position, sa: sa2 ? { dist: sa2.distance } : null });
}

