    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Click SA at (448, 360), then quickly read bubble
  await click(448, 360);
  await page.waitForTimeout(500);
  const bubble1 = await page.evaluate(() => document.getElementById('bubbles')?.innerHTML?.substring(0, 400));
  await page.waitForTimeout(2000);
  const pos = await page.evaluate(() => window.__latestGameState.player_position);

  // Click again to cycle dialogue
  const saInfo = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const sa = (gs.nearby_entities || []).find(e => e.name === 'Secret Agent');
    if (!sa) return null;
    const p = gs.player_position;
    return { dist: sa.distance, sx: 640 + (sa.x - p.x)*48, sy: 360 + (sa.y - p.y)*48 };
  });

  if (saInfo) {
    await click(saInfo.sx, saInfo.sy);
    await page.waitForTimeout(500);
  }
  const bubble2 = await page.evaluate(() => document.getElementById('bubbles')?.innerHTML?.substring(0, 400));

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return { bubble1, bubble2, pos, saInfo };
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Current pos: check
  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  const saX = 137, saY = 171;
  const sx = 640 + (saX - pos.x)*48;
  const sy = 360 + (saY - pos.y)*48;

  // Click through ALL 6 dialogue lines
  const bubbles = [];
  for (let i = 0; i < 6; i++) {
    await click(sx, sy);
    await page.waitForTimeout(800);
    const b = await page.evaluate(() => document.querySelector('.bubble p')?.textContent || '');
    bubbles.push(b);
  }

  // Now click quest button precisely when it appears
  const qBtn = await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    return { display: btn ? window.getComputedStyle(btn).display : 'none', text: btn?.textContent };
  });

  // Click quest button
  await page.evaluate(() => document.getElementById('quest-button')?.click());
  await page.waitForTimeout(1500);

  const questState = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs.quests.filter(q => q.key === 'codersglitch' || q.key === 'seaactivities').map(q => ({ key: q.key, stage: q.stage, started: q.started }));
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return { pos, sx, sy, bubbles, qBtn, questState };
}

async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // From (136, 171), cave entrance at ~(137, 168): sx=688, sy=216
  // Try different entrance tile positions
  for (const [x, y] of [[688, 216], [688, 168], [736, 216], [640, 216], [688, 264]]) {
    await click(x, y);
    await page.waitForTimeout(2000);
    const pos = await page.evaluate(() => window.__latestGameState.player_position);
    if (pos.x !== 136 || pos.y !== 171) {
      // Position changed - might be inside cave!
      const nearby = await page.evaluate(() => (window.__latestGameState.nearby_entities || []).filter(e => e.type === 1).map(e => ({ name: e.name, x: e.x, y: e.y })));
      await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
      return { moved: true, pos, clicked: [x, y], nearby };
    }
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  return { moved: false, pos };
}

