async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Walk toward Bubba - same y row, 5 tiles east
  await click(880, 360);
  await page.waitForTimeout(3000);
  const pos = await page.evaluate(() => window.__latestGameState.player_position);

  // Click Bubba with recalculated coords
  const bubbaInfo = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const b = (gs.nearby_entities || []).find(e => e.name === 'Bubba');
    const p = gs.player_position;
    return b ? { dist: b.distance, sx: 640+(b.x-p.x)*48, sy: 360+(b.y-p.y)*48 } : null;
  });

  if (bubbaInfo) {
    await click(Math.min(1270, bubbaInfo.sx), bubbaInfo.sy || 360);
    await page.waitForTimeout(1000);

    const bubbles = [];
    for (let i = 0; i < 5; i++) {
      const b2 = await page.evaluate(() => {
        const gs = window.__latestGameState;
        const bu = (gs.nearby_entities || []).find(e => e.name === 'Bubba');
        const p = gs.player_position;
        return bu ? { dist: bu.distance, sx: 640+(bu.x-p.x)*48, sy: 360+(bu.y-p.y)*48 } : null;
      });
      if (b2 && b2.dist <= 2) {
        await click(Math.min(1270, b2.sx), b2.sy || 360);
        await page.waitForTimeout(800);
        const txt = await page.evaluate(() => document.querySelector('.bubble p')?.textContent || '');
        const qb = await page.evaluate(() => {
          const btn = document.getElementById('quest-button');
          return { display: btn ? window.getComputedStyle(btn).display : 'none', text: btn?.textContent };
        });
        bubbles.push({ txt, questBtn: qb.text });
      }
    }

    await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
    return { pos, bubbaInfo, bubbles };
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return { pos, bubbaInfo };
}

