    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Go south toward beach (Bubba at 121, 231)
  await click(400, 720); await page.waitForTimeout(5000);
  let pos = await page.evaluate(() => window.__latestGameState?.player_position);
  console.log('S1: ' + JSON.stringify(pos));

  await click(350, 720); await page.waitForTimeout(5000);
  pos = await page.evaluate(() => window.__latestGameState?.player_position);
  console.log('S2: ' + JSON.stringify(pos));

  await click(300, 720); await page.waitForTimeout(5000);
  pos = await page.evaluate(() => window.__latestGameState?.player_position);
  console.log('S3: ' + JSON.stringify(pos));

  await click(250, 720); await page.waitForTimeout(5000);
  pos = await page.evaluate(() => window.__latestGameState?.player_position);

  const bubba = await page.evaluate(() => {
    const e = (window.__latestGameState?.nearby_entities || []).find(e => e.name === 'Bubba');
    return e ? {dist: e.distance} : null;
  });

  return JSON.stringify({pos, bubba});
}

async (page) => {
