  console.log('S2: ' + JSON.stringify(pos));

  // Now go west toward x=111 area
  await click(50, 360); await page.waitForTimeout(5000);
  pos = await page.evaluate(() => window.__latestGameState?.player_position);
  console.log('W: ' + JSON.stringify(pos));

  // Then go north to find Odd-Eyed Cat
  await click(400, 50); await page.waitForTimeout(5000);
  pos = await page.evaluate(() => window.__latestGameState?.player_position);

