async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true }));
  }, {x, y});

  // Navigate north toward Odd-Eyed Cat at (111, 149) from (112, 171)
  await click(500, 50); // north
  await page.waitForTimeout(5000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const cat = (gs.nearby_entities || []).find(e => e.name === 'Odd-Eyed Cat');
    return JSON.stringify({
      pos: gs.player_position,
      cat: cat ? {dist: cat.distance, cx: cat.click_x, cy: cat.click_y, x: cat.x, y: cat.y} : null,
      npcs: (gs.nearby_entities || []).filter(e => e.type === 1).slice(0,5).map(e => ({name: e.name, dist: e.distance}))
    });
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_2/state/screenshot.png', type: 'png' });
  return state;
}

