async (page) => {
  // Warp to Mudwich
  await page.evaluate(() => window.game.menu.warp.show());
  await page.waitForTimeout(800);
  await page.evaluate(() => document.getElementById('warp0').click());
  await page.waitForTimeout(4000);

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
